import React, { useCallback, useMemo, useState } from 'react';
import { LinErpListFilterBar, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatNumber, formatVnd } from '../../../utils/formatters';
import { MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import {
  Bar,
  BarChart,
  CartesianGrid,
  Legend,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import type { KpiMetrics, MonthlyTrendRow } from '../../../services/analytics/models';
import { AnalyticsReportShell } from '../../../components/report';

const TEST_ID = 'erp-phan-tich';
const PAGE_ID = 'baocao-phan-tich';

const PhanTichPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [kpi, setKpi] = useState<KpiMetrics | null>(null);
  const [trend, setTrend] = useState<MonthlyTrendRow[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    Promise.all([
      analyticsService.getKpiMetrics({ month, year }),
      analyticsService.getMonthlyTrend({ year }),
    ])
      .then(([k, t]) => {
        setKpi(k);
        setTrend(t);
      })
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [month, year, dispatch]);

  const chartData = trend.map(d => ({ name: `T${d.month}`, revenue: d.revenue, cogs: d.cogs }));

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        onDateChange={() => {}}
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
        leading={(
          <>
            <div data-testid={`${TEST_ID}-field-month`}>
              <Select label="Tháng" value={String(month)} onChange={e => setMonth(Number(e.target.value))} options={MONTH_OPTIONS} size="small" />
            </div>
            <div data-testid={`${TEST_ID}-field-year`}>
              <Select label="Năm" value={String(year)} onChange={e => setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
            </div>
          </>
        )}
      />
    ),
    [month, year, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Phân tích kinh doanh"
      titleIconClass="fas fa-chart-pie"
      loading={loading}
      hasData={!!kpi}
      suppressEmptyGate
      filters={listFilters}
      onLoad={handleLoad}
    >
      <div className={reportStyles.kpiGrid}>
        <div className={reportStyles.kpiCard}>
          <div className={reportStyles.kpiLabel}>Doanh thu</div>
          <div className={reportStyles.kpiValue}>{formatVnd(kpi?.revenue)}</div>
        </div>
        <div className={reportStyles.kpiCard}>
          <div className={reportStyles.kpiLabel}>Giá vốn</div>
          <div className={reportStyles.kpiValue}>{formatVnd(kpi?.cogs)}</div>
        </div>
        <div className={reportStyles.kpiCard}>
          <div className={reportStyles.kpiLabel}>Biên LN gộp</div>
          <div className={reportStyles.kpiValue}>{formatNumber(kpi?.grossMargin)}%</div>
        </div>
        <div className={reportStyles.kpiCard}>
          <div className={reportStyles.kpiLabel}>Đơn hàng</div>
          <div className={reportStyles.kpiValue}>{formatNumber(kpi?.orders)}</div>
        </div>
      </div>
      <div className={reportStyles.chartCard}>
        <ResponsiveContainer width="100%" height={280}>
          <BarChart data={chartData}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="name" />
            <YAxis tickFormatter={v => `${(Number(v) / 1e9).toFixed(1)}B`} />
            <Tooltip formatter={(v: number) => formatVnd(v)} />
            <Legend />
            <Bar dataKey="revenue" name="Doanh thu" fill="#1677ff" />
            <Bar dataKey="cogs" name="Giá vốn" fill="#fa8c16" />
          </BarChart>
        </ResponsiveContainer>
      </div>
    </AnalyticsReportShell>
  );
};

export default PhanTichPage;
